package metodos.oop.exercicios.domain;public class Usuario {    public String nameUser;    public String password;    public String verifyUser (String name, String pass){        if (name.length() >= 8)            return "your name was cadastred successfully";        System.out.println("Name required min 8 characters!");        if (pass.length() >= 8)            return "your password was cadastred successfully";        System.out.println("password required min eight characters");        if (name.length() >= 8 && pass.length() >= 8)            System.out.println("successfully logged in");        return "Login failed!";    }}